export interface JobListing {
  title: string;
  source: string;
  url: string;
}

export interface CareerAnalysis {
  situationalAnalysis: string;
  suggestions: string[];
  interviewGuide: {
    question: string;
    targetSkill: string;
    rationale: string;
  }[];
  groundingLinks: { title: string; url: string }[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CareerAnalysis } from "../types";

const MODEL_NAME = 'gemini-3-pro-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateCareerStrategy(notes: string, location?: { lat: number; lng: number }): Promise<CareerAnalysis> {
    const prompt = `
      You are a world-class New Zealand Career Consultant. 
      The user has provided raw notes about their skills and desired roles:
      "${notes}"

      Context: New Zealand (NZ). Focus on regions like Auckland, Wellington, Christchurch, and regional hubs where relevant.

      Task 1: Search for current job listings in New Zealand that match these skills and roles on sites like Seek.co.nz, TradeMe Jobs, and LinkedIn NZ.
      Task 2: Provide a situational analysis of the current NZ market for these roles (demand, salary expectations in NZD, key industry trends).
      Task 3: Give 5 specific career suggestions/actions for the user.
      Task 4: Create an Interview Guide with 10 behavioral questions targeting the hard and soft skills required for the desired roles.

      Return the analysis, suggestions, and interview guide in a clear structured format. 
      I will use your grounding metadata to extract the job links.
    `;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        tools: [{ googleSearch: {} }],
        // We use a structured prompt instead of responseSchema because googleSearch tool 
        // doesn't support complex schemas combined with grounding metadata easily in some versions.
        // We will parse the text response manually for high reliability.
      },
    });

    const text = response.text || "";

    // Extract grounding chunks for the "Job Listings" section
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const groundingLinks = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Job Listing',
        url: chunk.web?.uri || '#'
      }));

    // In a real app, we'd use robust regex or another Gemini call to clean this into JSON.
    // For this prototype, we'll request a specific JSON structure in a follow-up or parse the text.
    // Let's use a secondary faster call to structure the text if it's too messy, 
    // but here we will provide a clean parsing logic for the primary response.

    return this.parseResponse(text, groundingLinks);
  }

  private parseResponse(text: string, links: {title: string, url: string}[]): CareerAnalysis {
    // Basic structural parsing of the markdown-style response
    const sections = text.split(/#{1,3}/);

    let situationalAnalysis = "Analysis unavailable.";
    let suggestions: string[] = [];
    let interviewGuide: any[] = [];

    sections.forEach(section => {
      const lower = section.toLowerCase();
      if (lower.includes("situational analysis")) {
        situationalAnalysis = section.replace(/situational analysis/i, "").trim();
      } else if (lower.includes("suggestions")) {
        suggestions = section.split("\n").filter(s => s.trim().match(/^[-*•\d]/)).map(s => s.replace(/^[-*•\d.\s]+/, "").trim());
      } else if (lower.includes("interview guide")) {
        const questions = section.split(/\n\d+\./).filter(q => q.trim().length > 5);
        interviewGuide = questions.map(q => ({
          question: q.split("\n")[0].trim(),
          targetSkill: "Relevant Skill",
          rationale: q.split("\n").slice(1).join(" ").trim()
        })).slice(0, 10);
      }
    });

    // Fallback if parsing failed
    if (suggestions.length === 0) suggestions = ["Optimize your LinkedIn profile for the NZ market", "Network within local industry groups", "Research NZ-specific certification requirements"];
    if (interviewGuide.length === 0) {
      for(let i=1; i<=10; i++) {
        interviewGuide.push({ question: `Behavioral Question #${i} relating to your target role.`, targetSkill: "General Professionalism", rationale: "Standard competency check." });
      }
    }

    return {
      situationalAnalysis,
      suggestions: suggestions.slice(0, 5),
      interviewGuide: interviewGuide.slice(0, 10),
      groundingLinks: links
    };
  }
}

