import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CareerAnalysis } from "../types";

const MODEL_NAME = 'gemini-3-pro-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeRole(query: string): Promise<CareerAnalysis> {
    const prompt = `
      Perform an exhaustive professional analysis for the following career query in New Zealand:
      "${query}"

      Requirements:
      1. MARKET ANALYSIS: Current state of the NZ market for this specific role/location. Include demand levels (High/Medium/Low), key employers in NZ, and salary benchmarks in NZD.
      2. ADVERTISED ROLES: Use Google Search to find 5-8 live job listings from Seek.co.nz, TradeMe Jobs, LinkedIn NZ, or company career pages.
      3. REQUIREMENTS & SKILLS: List the essential technical skills, soft skills, and NZ-specific qualifications or certifications (e.g., CA/CPA for accounting, Site Safe for construction, etc.).
      4. STRATEGIC SUGGESTIONS: Provide a 5-step actionable strategy for a candidate to win this role in the current NZ climate.
      5. INTERVIEW GUIDE: 10 behavioral interview questions tailored to this role's specific hard and soft skill requirements, with the "Why" for each.

      IMPORTANT: 
      - Use New Zealand spelling (e.g., 'organisation', 'programme').
      - Provide the response in clear, titled sections using Markdown headers (###).
      - I will extract the grounding links from your metadata for the 'Advertised Roles' section.
    `;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";

    // Extract grounding chunks for the "Job Listings" section
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const groundingLinks = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Job Listing',
        url: chunk.web?.uri || '#'
      }));

    return this.parseResponse(text, groundingLinks);
  }

  private parseResponse(text: string, links: {title: string, url: string}[]): CareerAnalysis {
    const sections = text.split(/#{1,3}/);

    let situationalAnalysis = "Detailed analysis processing...";
    let suggestions: string[] = [];
    let interviewGuide: any[] = [];

    sections.forEach(section => {
      const lower = section.toLowerCase();
      if (lower.includes("market analysis") || lower.includes("situational analysis")) {
        situationalAnalysis = section.replace(/market analysis|situational analysis/i, "").trim();
      } else if (lower.includes("strategy") || lower.includes("suggestions")) {
        suggestions = section.split("\n")
          .filter(s => s.trim().match(/^[-*•\d]/))
          .map(s => s.replace(/^[-*•\d.\s]+/, "").trim());
      } else if (lower.includes("interview guide")) {
        const questions = section.split(/\n\d+\./).filter(q => q.trim().length > 10);
        interviewGuide = questions.map(q => {
          const lines = q.trim().split('\n');
          return {
            question: lines[0].trim(),
            targetSkill: "Core Competency",
            rationale: lines.slice(1).join(" ").trim() || "Critical for assessing fit in the NZ market."
          };
        }).slice(0, 10);
      }
    });

    // Fallbacks
    if (suggestions.length === 0) {
      suggestions = [
        "Tailor your CV to emphasize NZ-specific experience or local context.",
        "Update your LinkedIn location to the target NZ city.",
        "Research the top 3 employers mentioned in the analysis.",
        "Network via local industry meetups (e.g., NZTech, CA ANZ events).",
        "Prepare 'STAR' method examples for the behavioral questions provided."
      ];
    }

    return {
      situationalAnalysis,
      suggestions: suggestions.slice(0, 5),
      interviewGuide: interviewGuide.length > 0 ? interviewGuide : this.getFallbackInterviewQuestions(),
      groundingLinks: links
    };
  }

  private getFallbackInterviewQuestions() {
    return Array(10).fill(0).map((_, i) => ({
      question: `Question ${i+1}: Tell me about a time you handled a complex challenge in a team environment.`,
      targetSkill: "Teamwork & Problem Solving",
      rationale: "NZ workplaces value collaboration and the 'can-do' attitude."
    }));
  }
}

