import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CareerAnalysis, InterviewQuestion, StrategyItem } from "../types";

const MODEL_NAME = 'gemini-3-pro-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzeRole(query: string): Promise<CareerAnalysis> {
    const prompt = `
      Perform an exhaustive career intelligence analysis for: "${query}" in the New Zealand context.

      You must provide a dual-part response:
      1. A conversational markdown summary of the market.
      2. A strictly formatted JSON block wrapped in \`\`\`json tags containing the structured data below.

      JSON STRUCTURE REQUIRED:
      {
        "roleName": "Specific Role Title",
        "locationName": "City/Region in NZ",
        "summary": "Brief 2-sentence market pulse",
        "marketStats": {
          "demandScore": 1-10,
          "salaryData": [{"level": "Junior", "min": 60000, "max": 80000}, ...],
          "topSkills": [{"name": "Skill Name", "importance": 85, "demand": "Growing"}, ...],
          "marketOutlook": "Detailed outlook text"
        },
        "suggestions": [
          {
            "title": "...", 
            "description": "...", 
            "timeline": "...", 
            "level": "Entry/Junior/Mid-Senior/Senior/General"
          }
        ],
        "interviewGuide": [
          {
            "question": "...", 
            "category": "Behavioral/Technical/Cultural/Situational", 
            "rationale": "Why NZ employers ask this specifically", 
            "technique": "Detailed explanation of the technique to use",
            "exampleAnswer": "..."
          }
        ]
      }

      GUIDELINES FOR STRATEGY:
      - Provide at least 2 specific strategies for EACH level: Entry, Junior, Mid-Senior, Senior.
      - Ensure 'level' strictly matches one of the specified strings.

      GUIDELINES FOR INTERVIEW GUIDE:
      - Provide 15 distinct questions.
      - Mix: 7 Behavioral, 5 Technical, 3 Cultural/Situational.

      Additionally, use the Google Search tool to find 5-8 live job listings on Seek.co.nz, TradeMe Jobs, or LinkedIn NZ for this role and location.

      IMPORTANT: NZ Context, NZD currency, NZ English.
    `;

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 32768 },
        tools: [{ googleSearch: {} }],
      },
    });

    const text = response.text || "";

    // Extract grounding
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const groundingLinks = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || 'Job Listing',
        url: chunk.web?.uri || '#'
      }));

    return this.parseResponse(text, groundingLinks);
  }

  private parseResponse(text: string, links: {title: string, url: string}[]): CareerAnalysis {
    let jsonData: any = {};

    try {
      const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/```json([\s\S]*?)```/);
      if (jsonMatch) {
        jsonData = JSON.parse(jsonMatch[1]);
      }
    } catch (e) {
      console.error("Failed to parse JSON from response", e);
    }

    const guide: InterviewQuestion[] = (jsonData.interviewGuide || []).map((item: any) => ({
      question: item.question || "Standard Interview Question",
      category: item.category || "Behavioral",
      rationale: item.rationale || "Assessing core competency.",
      technique: item.technique || "Use the STAR method.",
      exampleAnswer: item.exampleAnswer || "Sample answer not provided."
    }));

    const suggestions: StrategyItem[] = (jsonData.suggestions || []).map((item: any) => ({
      title: item.title || "Strategic Step",
      description: item.description || "Actionable detail.",
      timeline: item.timeline || "Immediate",
      level: item.level || "General"
    }));

    return {
      roleName: jsonData.roleName || "The Analyzed Role",
      locationName: jsonData.locationName || "New Zealand",
      summary: jsonData.summary || "Highly active market.",
      marketStats: jsonData.marketStats || {
        demandScore: 7,
        salaryData: [],
        topSkills: [],
        marketOutlook: ""
      },
      suggestions,
      interviewGuide: guide,
      groundingLinks: links
    };
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ChatMessage, CareerAnalysis } from '../types';

interface Props {
  context?: CareerAnalysis | null;
}

const ChatBot: React.FC<Props> = ({ context }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const sampleQuestions = [
    "Summarise the dashboard",
    "Explain Core Competency Focus",
    "What do you mean by Market Demand Card?",
    "How can I negotiate salary in NZ?"
  ];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async (textToSend?: string) => {
    const messageText = textToSend || input;
    if (!messageText.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: messageText };
    setMessages(prev => [...prev, userMsg]);
    if (!textToSend) setInput('');
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let systemInstruction = `You are a helpful NZ Career Assistant. 
      IMPORTANT FORMATTING RULES:
      - Reply line-by-line. 
      - Use clear line breaks between every sentence or point. 
      - Keep language extremely simple and easy to read. 
      - Use bullet points for any lists. 
      - Avoid long paragraphs. 
      - Be concise but highly practical.`;

      if (context) {
        systemInstruction += `\n\nCURRENT CONTEXT:
        Role: "${context.roleName}"
        Location: "${context.locationName}"
        Market Demand Score: ${context.marketStats.demandScore}/10. 
        Top Skills: ${context.marketStats.topSkills.map(s => s.name).join(', ')}.
        Focus follow-up questions strictly on this analysis (roles, interview guide, or strategy). 
        If asked something unrelated, briefly guide them back to their career strategy.`;
      }

      const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        config: { systemInstruction }
      });

      const response = await chat.sendMessage({ message: messageText });
      const botMsg: ChatMessage = { role: 'model', text: response.text || "Sorry, I couldn't process that." };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Connection error.\nPlease try again." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white w-80 md:w-[400px] h-[600px] shadow-2xl rounded-3xl border border-slate-200 flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
          {/* Header */}
          <div className="bg-slate-900 p-5 flex items-center justify-between text-white">
            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(52,211,153,0.5)]"></div>
              <div>
                <span className="font-black text-sm block">NZ Career Assistant</span>
                {context && <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Context: {context.roleName}</span>}
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-slate-800 rounded-xl p-2 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Messages */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
            {messages.length === 0 && (
              <div className="text-center mt-6 space-y-6">
                <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto shadow-sm border border-slate-100">
                  <svg className="w-8 h-8 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                  </svg>
                </div>
                <div>
                  <p className="text-slate-800 font-black text-lg">How can I help you today?</p>
                  <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1 px-8">Ask about the dashboard insights, interview tips, or strategy adjustments.</p>
                </div>

                {/* Sample Question Chips */}
                <div className="flex flex-wrap justify-center gap-2 px-4">
                  {sampleQuestions.map((q, i) => (
                    <button
                      key={i}
                      onClick={() => handleSendMessage(q)}
                      className="text-[11px] font-bold bg-white border border-slate-200 text-slate-600 px-3 py-2 rounded-xl hover:border-indigo-600 hover:text-indigo-600 transition-all shadow-sm"
                    >
                      {q}
                    </button>
                  ))}
                </div>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap ${
                  m.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-br-none shadow-xl shadow-slate-200' 
                  : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none shadow-sm font-medium'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white p-4 rounded-2xl text-slate-300 flex gap-1 shadow-sm border border-slate-100">
                  <span className="animate-bounce">●</span>
                  <span className="animate-bounce delay-100">●</span>
                  <span className="animate-bounce delay-200">●</span>
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 bg-white border-t border-slate-100 flex gap-3">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Ask a follow-up question..."
              className="flex-1 bg-slate-50 border-none rounded-2xl px-5 py-4 text-sm font-bold placeholder-slate-300 focus:ring-2 focus:ring-slate-900 outline-none transition-all"
            />
            <button
              onClick={() => handleSendMessage()}
              disabled={isTyping}
