import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ChatMessage, CareerAnalysis } from '../types';

interface Props {
  context?: CareerAnalysis | null;
}

const ChatBot: React.FC<Props> = ({ context }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const withRetry = async <T,>(fn: () => Promise<T>, maxRetries = 3, baseDelay = 3000): Promise<T> => {
    let lastError: any;
    for (let i = 0; i < maxRetries; i++) {
      try {
        return await fn();
      } catch (error: any) {
        lastError = error;
        const errorText = error.message || error.toString();
        const isRateLimit = errorText.includes('429') || error.status === 429 || errorText.includes('RESOURCE_EXHAUSTED');
        if (isRateLimit && i < maxRetries - 1) {
          const delay = baseDelay * Math.pow(2, i);
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }
        throw error;
      }
    }
    throw lastError;
  };

  const handleSendMessage = async (textToSend?: string) => {
    const messageText = textToSend || input;
    if (!messageText.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: messageText };
    setMessages(prev => [...prev, userMsg]);
    if (!textToSend) setInput('');
    setIsTyping(true);

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("API Key Missing");

      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `You are a direct NZ Career Assistant. Answer ONLY the question asked. No filler. Line-by-line reply. 
      ${context ? `Context: Role "${context.roleName}", Location "${context.locationName}".` : ''}`;

      const chat = ai.chats.create({
        model: 'gemini-3-pro-preview',
        config: { systemInstruction }
      });

      const response: GenerateContentResponse = await withRetry(() => chat.sendMessage({ message: messageText }));
      const botMsg: ChatMessage = { role: 'model', text: response.text || "I couldn't get a response." };
      setMessages(prev => [...prev, botMsg]);
    } catch (error: any) {
      console.error(error);
      const errorText = error.message || error.toString();
      let errorMsg = "I encountered an error. Please try again.";
      if (errorText.includes('429') || error.status === 429 || errorText.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = "🛑 Rate limit reached. The Google API is resting. Please wait ~60 seconds and try your question again.";
      }
      setMessages(prev => [...prev, { role: 'model', text: errorMsg }]);
    } finally {
      setIsTyping(false);
    }
  };

  const sampleQuestions = ["Summarise dashboard", "NZ Salary negotiation", "Explain Demand Score"];

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white w-80 md:w-[400px] h-[600px] shadow-2xl rounded-3xl border border-slate-200 flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
          <div className="bg-slate-900 p-5 flex items-center justify-between text-white">
            <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 bg-emerald-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(52,211,153,0.5)]"></div>
              <div>
                <span className="font-black text-sm block">NZ Assistant</span>
                {context && <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{context.roleName}</span>}
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-slate-800 rounded-xl p-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50">
            {messages.length === 0 && (
              <div className="text-center mt-6 space-y-6">
                <p className="text-slate-800 font-black text-lg">Direct follow-up help.</p>
                <div className="flex flex-wrap justify-center gap-2">
                  {sampleQuestions.map((q, i) => (
                    <button key={i} onClick={() => handleSendMessage(q)} className="text-[10px] font-black uppercase tracking-tight bg-white border border-slate-200 px-3 py-2 rounded-xl hover:border-indigo-600">
                      {q}
                    </button>
                  ))}
                </div>
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap ${
                  m.role === 'user' ? 'bg-slate-900 text-white rounded-br-none shadow-xl' : 'bg-white text-slate-800 border border-slate-200 rounded-bl-none shadow-sm'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white p-4 rounded-2xl text-slate-300 flex gap-1 shadow-sm border border-slate-100">
                  <span className="animate-bounce">●</span>
                  <span className="animate-bounce delay-100">●</span>
                  <span className="animate-bounce delay-200">●</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-100 flex flex-col gap-3">
            <div className="flex gap-3">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Type your question..."
                className="flex-1 bg-slate-50 border-none rounded-2xl px-5 py-4 text-sm font-bold focus:ring-2 focus:ring-slate-900 outline-none"
              />
              <button onClick={() => handleSendMessage()} disabled={isTyping} className="bg-slate-900 text-white p-4 rounded-2xl shadow-lg">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
              </button>
            </div>
          </div>
        </div>
      ) : (
        <button onClick={() => setIsOpen(true)} className="bg-slate-900 text-white p-5 rounded-full shadow-2xl hover:bg-black transition-all flex items-center gap-3">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
          <span className="hidden md:inline font-black text-sm uppercase tracking-widest">Ask Assistant</span>
        </button>
      )}
    </div>
  );
};

export default ChatBot;

