import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { CareerAnalysis } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  constructor() {}

  private async withRetry<T>(fn: () => Promise<T>, maxRetries = 3, baseDelay = 3000): Promise<T> {
    let lastError: any;
    for (let i = 0; i < maxRetries; i++) {
      try {
        return await fn();
      } catch (error: any) {
        lastError = error;
        const errorText = error.message || error.toString();
        const isRetryable = errorText.includes('429') || 
                           error.status === 429 || 
                           errorText.includes('RESOURCE_EXHAUSTED');

        if (isRetryable && i < maxRetries - 1) {
          const delay = baseDelay * Math.pow(2, i);
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }
        throw error;
      }
    }
    throw lastError;
  }

  async analyzeRole(roleQuery: string, skillsNotes: string): Promise<CareerAnalysis> {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("API_KEY_NOT_FOUND");
    }

    const ai = new GoogleGenAI({ apiKey });
    const isNational = !roleQuery.toLowerCase().match(/(auckland|wellington|christchurch|hamilton|tauranga|dunedin|palmerston|nelson|napier|hastings|rotorua|whangarei|new plymouth|invercargill|whanganui|gisborne)/);

    const prompt = `
      Perform a highly personalized career analysis for a user in New Zealand.

      TARGET ROLES: "${roleQuery}"
      USER BACKGROUND NOTES: "${skillsNotes}"

      Context: 
      1. New Zealand market (NZD, NZ English).
      2. Analyze the 'GAP' between the user's skills and the roles they want.
      3. Use Google Search to find 5-8 live listings on Seek or TradeMe.

      Required JSON block in \`\`\`json tags:
      {
        "roleName": "Primary Role Target",
        "locationName": "Target Region",
        "summary": "2-sentence pulse on the market for this specific combo",
        "nzProTip": "A 10-word tip for NZ job hunters specific to this user's profile",
        "skillGapAnalysis": "A 3-sentence summary of how well the user's provided 'background notes' match the current target role requirements.",
        "marketStats": {
          "demandScore": 1-10,
          "salaryData": [{"level": "Junior", "min": 60000, "max": 80000}, {"level": "Mid", "min": 85000, "max": 110000}, {"level": "Senior", "min": 120000, "max": 160000}],
          "topSkills": [{"name": "Skill Name", "importance": 85, "demand": "Growing", "userMatch": 0-100}],
          "marketOutlook": "Market outlook text",
          "cityComparison": [{"city": "Auckland", "value": 8}, {"city": "Wellington", "value": 7}, {"city": "Christchurch", "value": 5}]
        },
        "suggestions": [{"title": "Personalized Action", "description": "Specific move based on their background", "timeline": "Immediately", "level": "General"}],
        "interviewGuide": [{"question": "Q", "category": "Behavioral", "rationale": "NZ context", "technique": "STAR focus", "exampleAnswer": "Sample"}]
      }
    `;

    try {
      const response: GenerateContentResponse = await this.withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: MODEL_NAME,
        contents: prompt,
        config: {
          thinkingConfig: { thinkingBudget: 15000 },
          tools: [{ googleSearch: {} }],
        },
      }));

      const text = response.text || "";
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const groundingLinks = groundingChunks
        .filter(chunk => chunk.web)
        .map(chunk => ({
          title: chunk.web?.title || 'Job Listing',
          url: chunk.web?.uri || '#'
        }));

      return this.parseResponse(text, groundingLinks);
    } catch (error: any) {
      throw error;
    }
  }

  private parseResponse(text: string, links: {title: string, url: string}[]): CareerAnalysis {
    let jsonData: any = {};
    try {
      const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/```json([\s\S]*?)```/);
      const content = jsonMatch ? jsonMatch[1] : text.replace(/^[^{]*/, '').replace(/[^}]*$/, '');
      jsonData = JSON.parse(content);
    } catch (e) {
      console.error("JSON Parse Error", e);
    }

    return {
      roleName: jsonData.roleName || "The Role",
      locationName: jsonData.locationName || "New Zealand",
      summary: jsonData.summary || "Analyzing the market for your profile.",
      nzProTip: jsonData.nzProTip || "Highlight transferable skills and cultural fit for NZ teams.",
      skillGapAnalysis: jsonData.skillGapAnalysis || "No background details provided for a match check.",
      marketStats: jsonData.marketStats || { demandScore: 5, salaryData: [], topSkills: [], marketOutlook: "" },
      suggestions: jsonData.suggestions || [],
      interviewGuide: jsonData.interviewGuide || [],
      groundingLinks: links
    };
  }
}

